// Parse and validate the incoming CyberSentinel alert
const alert = $input.first().json;

// Normalize severity
const severity = (alert.severity || 'UNKNOWN').toUpperCase();
const type = alert.type || 'UNKNOWN';
const srcIp = alert.src_ip || 'N/A';
const dstIp = alert.dst_ip || 'N/A';
const mitre = alert.matched_mitre || alert.mitre_technique || 'N/A';
const score = alert.anomaly_score || alert.rlm_anomaly_score || 0;
const timestamp = alert.timestamp || new Date().toISOString();

// Generate incident ID
const incidentId = `INC-${Date.now()}`;

// Determine response playbook based on threat type
let playbook = 'STANDARD';
if (type === 'C2_BEACON_DETECTED') playbook = 'C2_RESPONSE';
else if (type === 'ACTIVE_EXPLOITATION') playbook = 'EXPLOIT_RESPONSE';
else if (type === 'CRITICAL_CVE') playbook = 'CVE_RESPONSE';
else if (mitre === 'T1486') playbook = 'RANSOMWARE_RESPONSE';
else if (mitre === 'T1048') playbook = 'EXFIL_RESPONSE';

// Severity emoji mapping
const emoji = { CRITICAL: '🚨', HIGH: '🔴', MEDIUM: '🟠', LOW: '🟡' };

return [{
  json: {
    ...alert,
    incidentId,
    severity,
    type,
    srcIp,
    dstIp,
    mitre,
    score: parseFloat(score).toFixed(3),
    timestamp,
    playbook,
    emoji: emoji[severity] || '⚠️',
    humanTime: new Date(timestamp).toUTCString(),
    requiresAutoBlock: severity === 'CRITICAL' && score > 0.8,
    requiresIsolation: playbook === 'RANSOMWARE_RESPONSE' || playbook === 'C2_RESPONSE',
  }
}];

// Merge host intel + IP reputation with alert data
const alert = $('Parse & Enrich Alert').item.json;
const hostData = $('Get Host Intelligence').item.json;
const abuseData = $('Check IP Reputation (AbuseIPDB)').item.json?.data || {};

const abuseScore = abuseData.abuseConfidenceScore || 0;
const country = abuseData.countryCode || 'Unknown';
const isp = abuseData.isp || 'Unknown';
const totalReports = abuseData.totalReports || 0;

const profile = hostData.profile || {};
const anomalyScore = profile.anomaly_score || alert.anomaly_score || 0;
const observationCount = profile.observation_count || 0;

// Combined threat score (weighted average)
const combinedScore = (
  parseFloat(anomalyScore) * 0.6 +
  (abuseScore / 100) * 0.4
).toFixed(3);

// Final verdict
let verdict = 'INVESTIGATE';
if (combinedScore > 0.75 || abuseScore > 80) verdict = 'MALICIOUS_CONFIRMED';
else if (combinedScore > 0.5 || abuseScore > 50) verdict = 'LIKELY_MALICIOUS';
else if (combinedScore < 0.2 && abuseScore < 10) verdict = 'LIKELY_BENIGN';

return [{
  json: {
    ...alert,
    hostIntel: {
      isBlocked: hostData.is_blocked || false,
      isIsolated: hostData.is_isolated || false,
      blockCount: hostData.block_count || 0,
      profile: profile,
    },
    ipReputation: { abuseScore, country, isp, totalReports },
    combinedScore,
    verdict,
    shouldBlock: verdict === 'MALICIOUS_CONFIRMED' && !hostData.is_blocked,
    shouldCreateTicket: true,
    shouldPage: alert.severity === 'CRITICAL',
  }
}];

